+	msg := PropulsionNudgeForRole("mayor", "")
+	if strings.Contains(msg, "[session:") {
+		t.Errorf("PropulsionNudgeForRole(mayor, \"\") = %q, should NOT contain session ID", msg)
+	}
+}
+
+func TestPropulsionNudgeForRole_AllRoles(t *testing.T) {
+	tests := []struct {
