+		{"crew", "gt hook"},
+		{"witness", "gt prime"},
+		{"refinery", "gt prime"},
+		{"deacon", "gt prime"},
+		{"mayor", "gt prime"},
+		{"unknown", "gt hook"},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.role, func(t *testing.T) {
+			msg := PropulsionNudgeForRole(tt.role, "")
+			if !strings.Contains(msg, tt.contains) {
+				t.Errorf("PropulsionNudgeForRole(%q, \"\") = %q, should contain %q", tt.role, msg, tt.contains)
